//! Numerical parity tests: cross-validate Peregrine against PyTorch reference data.
//!
//! Reference data is generated by `tests/generate_reference.py`.
//! Run: cargo test --test pytorch_parity

use peregrine::nn;
use peregrine::optim::Adam;
use peregrine::tensor::Tensor;
use std::fs::File;
use std::io::Read;

const FIXTURES: &str = "tests/fixtures";

// --- Binary format helpers ---

fn load_tensor(path: &str) -> (Vec<usize>, Vec<f32>) {
    let mut file = File::open(path).unwrap_or_else(|_| {
        panic!(
            "Missing fixture: {}. Run: .venv/bin/python tests/generate_reference.py",
            path
        );
    });
    let mut buf = Vec::new();
    file.read_to_end(&mut buf).unwrap();

    let ndim = u32::from_le_bytes([buf[0], buf[1], buf[2], buf[3]]) as usize;
    let mut shape = Vec::with_capacity(ndim);
    for i in 0..ndim {
        let off = 4 + i * 4;
        shape.push(u32::from_le_bytes([buf[off], buf[off + 1], buf[off + 2], buf[off + 3]]) as usize);
    }
    let data_offset = 4 + ndim * 4;
    let num_floats = shape.iter().product::<usize>();
    let mut data = Vec::with_capacity(num_floats);
    for i in 0..num_floats {
        let off = data_offset + i * 4;
        data.push(f32::from_le_bytes([buf[off], buf[off + 1], buf[off + 2], buf[off + 3]]));
    }
    (shape, data)
}

fn load_vec_u32(path: &str) -> Vec<usize> {
    let mut file = File::open(path).unwrap();
    let mut buf = Vec::new();
    file.read_to_end(&mut buf).unwrap();

    let len = u32::from_le_bytes([buf[0], buf[1], buf[2], buf[3]]) as usize;
    let mut v = Vec::with_capacity(len);
    for i in 0..len {
        let off = 4 + i * 4;
        v.push(u32::from_le_bytes([buf[off], buf[off + 1], buf[off + 2], buf[off + 3]]) as usize);
    }
    v
}

fn load_peregrine(path: &str) -> Tensor {
    let (shape, data) = load_tensor(path);
    Tensor::new(data, shape, false)
}

fn load_peregrine_param(path: &str) -> Tensor {
    let (shape, data) = load_tensor(path);
    Tensor::new(data, shape, true)
}

fn max_abs_error(a: &[f32], b: &[f32]) -> f32 {
    assert_eq!(a.len(), b.len(), "length mismatch: {} vs {}", a.len(), b.len());
    a.iter()
        .zip(b.iter())
        .map(|(x, y)| (x - y).abs())
        .fold(0.0f32, f32::max)
}

fn max_rel_error(a: &[f32], b: &[f32]) -> f32 {
    assert_eq!(a.len(), b.len());
    a.iter()
        .zip(b.iter())
        .map(|(x, y)| {
            let denom = x.abs().max(y.abs()).max(1e-8);
            (x - y).abs() / denom
        })
        .fold(0.0f32, f32::max)
}

// --- Tests ---

#[test]
fn parity_matmul() {
    let a = load_peregrine(&format!("{FIXTURES}/matmul_a.bin"));
    let b = load_peregrine(&format!("{FIXTURES}/matmul_b.bin"));
    let (_, expected) = load_tensor(&format!("{FIXTURES}/matmul_c.bin"));

    let c = a.matmul(&b);
    let err = max_abs_error(&c.data(), &expected);
    assert!(err < 1e-4, "matmul max abs error: {err}");
}

