#[test]
fn parity_cross_entropy() {
    let logits = load_peregrine(&format!("{FIXTURES}/ce_logits.bin"));
    let targets = load_vec_u32(&format!("{FIXTURES}/ce_targets.bin"));
    let (_, expected) = load_tensor(&format!("{FIXTURES}/ce_loss.bin"));

    let loss = nn::cross_entropy_loss(&logits, &targets);
    let err = (loss.data()[0] - expected[0]).abs();
    assert!(err < 1e-5, "cross_entropy max abs error: {err} (got {}, expected {})", loss.data()[0], expected[0]);
}

