#[test]
fn parity_adam_step() {
    let (shape, w_data) = load_tensor(&format!("{FIXTURES}/adam_w_init.bin"));
    let (_, grad_data) = load_tensor(&format!("{FIXTURES}/adam_grad.bin"));
    let (_, expected) = load_tensor(&format!("{FIXTURES}/adam_w_after.bin"));

    // Create a parameter tensor with the initial weights
    let w = Tensor::new(w_data, shape, true);

    // Manually set the gradient to match PyTorch's gradient
    w.set_grad(grad_data);

    // Run one Adam step
    let mut opt = Adam::new(vec![w.clone()], 1e-3);
    opt.step();

    let err = max_abs_error(&w.data(), &expected);
    assert!(err < 1e-6, "adam step max abs error: {err}");
}

#[test]
fn parity_mlp_training() {
    // Load initial weights (same as PyTorch)
    let w1 = load_peregrine_param(&format!("{FIXTURES}/mlp_w1.bin"));
    let b1 = load_peregrine_param(&format!("{FIXTURES}/mlp_b1.bin"));
    let w2 = load_peregrine_param(&format!("{FIXTURES}/mlp_w2.bin"));
    let b2 = load_peregrine_param(&format!("{FIXTURES}/mlp_b2.bin"));
    let w3 = load_peregrine_param(&format!("{FIXTURES}/mlp_w3.bin"));
    let b3 = load_peregrine_param(&format!("{FIXTURES}/mlp_b3.bin"));

    let x_train = load_peregrine(&format!("{FIXTURES}/mlp_x_train.bin"));
    let targets = load_vec_u32(&format!("{FIXTURES}/mlp_targets_train.bin"));

    let (_, expected_losses) = load_tensor(&format!("{FIXTURES}/mlp_losses.bin"));
    let (_, expected_w1) = load_tensor(&format!("{FIXTURES}/mlp_w1_final.bin"));
    let (_, expected_w2) = load_tensor(&format!("{FIXTURES}/mlp_w2_final.bin"));
    let (_, expected_w3) = load_tensor(&format!("{FIXTURES}/mlp_w3_final.bin"));

    let params = vec![
        w1.clone(), b1.clone(), w2.clone(), b2.clone(), w3.clone(), b3.clone(),
    ];
    let mut opt = Adam::new(params, 1e-3);

    let mut losses = Vec::new();
    for step in 0..10 {
        // Forward: h1 = relu(x @ w1 + b1)
        let h1 = x_train.matmul(&w1).add_bias(&b1).relu();
        // h2 = relu(h1 @ w2 + b2)
        let h2 = h1.matmul(&w2).add_bias(&b2).relu();
        // logits = h2 @ w3 + b3
        let logits = h2.matmul(&w3).add_bias(&b3);

        let loss = nn::cross_entropy_loss(&logits, &targets);
        let loss_val = loss.data()[0];
        losses.push(loss_val);

        // Check loss matches PyTorch at each step
        let loss_err = (loss_val - expected_losses[step]).abs();
        let rel_err = loss_err / expected_losses[step].abs().max(1e-8);
        assert!(
            rel_err < 1e-4,
            "step {step}: loss relative error {rel_err} (peregrine={loss_val}, pytorch={})",
            expected_losses[step]
        );

        loss.backward();
        opt.step();
        opt.zero_grad();
    }

    // Check final weights
    let w1_err = max_rel_error(&w1.data(), &expected_w1);
    let w2_err = max_rel_error(&w2.data(), &expected_w2);
    let w3_err = max_rel_error(&w3.data(), &expected_w3);

    assert!(w1_err < 1e-3, "w1 final max rel error: {w1_err}");
    assert!(w2_err < 1e-3, "w2 final max rel error: {w2_err}");
    assert!(w3_err < 1e-3, "w3 final max rel error: {w3_err}");
}
